public class ScratchPad {

    public static void main(String[] args) {
        int[] arr1 = {3, 4, 5, 3, 7, 2};
        int k1 = 3;

        System.out.println("Difference for arr1: " + splitArray(arr1, k1));
    }

    public static int splitArray(int[] arr, int k) {
        int low = getMax(arr);
        int high = getSum(arr);
        int max = 0;
        int min = 0;

        while(low <= high) {
            int mid = low + (high - low) / 2;
            int[] partial = isPossible(arr, k, mid);

            if(partial[0] == 1) {
                max = mid;
                min = partial[1];
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        System.out.println("Max and Min: " + max + " " + min);
        return max - min;
    }

    private static int[] isPossible(int[] arr, int k, int mid) {
        int count = 1;
        int sum = 0;
        int min = Integer.MAX_VALUE;

        for(int b : arr) {
            sum += b;
            if(sum > mid) {
                min = Math.min(min, sum - b);
                count++;
                sum = b;
            }
        }

        return new int[]{count <= k ? 1 : 0, Math.min(min, sum)};
    }

    private static int getMax(int[] arr) {
        int max = arr[0];
        for(int i = 1; i < arr.length; i++) {
            if(arr[i] > max) {
                max = arr[i];
            }
        }
        return max;
    }

    private static int getSum(int[] arr) {
        int sum = 0;
        for(int val : arr) {
            sum += val;
        }
        return sum;
    }
}


